import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.D5wUhsuj.js";const u=JSON.parse('{"title":"Storage Administration","description":"","frontmatter":{},"headers":[],"relativePath":"admin/storage.md","filePath":"admin/storage.md","lastUpdated":1783543014000}'),r={name:"admin/storage.md"};function i(n,e,d,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="storage-administration" tabindex="-1">Storage Administration <a class="header-anchor" href="#storage-administration" aria-label="Permalink to &quot;Storage Administration&quot;">​</a></h1><p>prokube uses Kubernetes storage for workspace volumes, notebook homes, databases, object-storage tenants, pipeline artifacts, and model-serving data. Storage behavior is deployment-specific and depends on the installed StorageClasses and CSI drivers.</p><h2 id="storageclasses" tabindex="-1">StorageClasses <a class="header-anchor" href="#storageclasses" aria-label="Permalink to &quot;StorageClasses&quot;">​</a></h2><p>Inspect the live cluster before making assumptions:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> storageclass</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pvc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span></span></code></pre></div><p>For each StorageClass, record:</p><ul><li>access modes supported by the provisioner;</li><li>whether volume expansion is allowed;</li><li>whether snapshots are supported;</li><li>reclaim policy;</li><li>node-local versus replicated behavior;</li><li>intended workload type.</li></ul><h2 id="local-storage" tabindex="-1">Local Storage <a class="header-anchor" href="#local-storage" aria-label="Permalink to &quot;Local Storage&quot;">​</a></h2><p>OpenEBS LocalPV and similar local-path provisioners can provide fast node-local volumes, often with class names such as <code>openebs-hostpath</code>. This is useful for small single-node deployments and temporary or easily recreated data.</p><p>Node-local storage is not portable across nodes. A pod using a <code>ReadWriteOnce</code> local volume must run on the node where the data exists. If the node is lost, the volume can be lost too unless another backup exists.</p><p>Use local storage only when the availability tradeoff is acceptable.</p><h2 id="replicated-storage" tabindex="-1">Replicated Storage <a class="header-anchor" href="#replicated-storage" aria-label="Permalink to &quot;Replicated Storage&quot;">​</a></h2><p>Mayastor/OpenEBS replicated storage can provide synchronous replicas across nodes when the deployment is configured for it. Class names vary by deployment; examples include no-redundancy and three-replica classes.</p><p>Replication improves availability for node or disk failure, but it is not backup. Replication also adds capacity and performance tradeoffs because each replica consumes storage and network bandwidth.</p><p>Use replicated storage for stateful components that need higher availability, such as databases or object-storage volumes, when the cluster has enough nodes and disks to support the replica count.</p><h2 id="component-usage" tabindex="-1">Component Usage <a class="header-anchor" href="#component-usage" aria-label="Permalink to &quot;Component Usage&quot;">​</a></h2><p>Typical storage choices:</p><table tabindex="0"><thead><tr><th>Component</th><th>Storage considerations</th></tr></thead><tbody><tr><td>Labs</td><td>Persistent home volumes are convenient for interactive work but can be constrained by <code>ReadWriteOnce</code> attachment.</td></tr><tr><td>Pipelines</td><td>Prefer object storage for artifacts and datasets instead of relying on Lab volumes.</td></tr><tr><td>MLflow</td><td>Metadata and artifacts need backup; artifact storage can grow quickly.</td></tr><tr><td>MinIO</td><td>Tenant volumes require deliberate sizing, backup, and migration planning.</td></tr><tr><td>Databases</td><td>Use storage with snapshot/backup support and predictable latency.</td></tr><tr><td>Model Serving</td><td>Large models should live in object storage or MLflow, with optional cache support where configured.</td></tr></tbody></table><h2 id="troubleshooting-pvcs" tabindex="-1">Troubleshooting PVCs <a class="header-anchor" href="#troubleshooting-pvcs" aria-label="Permalink to &quot;Troubleshooting PVCs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Check</th></tr></thead><tbody><tr><td>PVC remains pending</td><td>StorageClass name, provisioner health, capacity, allowed topology, and quota.</td></tr><tr><td>Pod cannot attach volume</td><td>Existing attachment to another node, <code>ReadWriteOnce</code> constraints, stale <code>VolumeAttachment</code>, or node failure.</td></tr><tr><td>Volume expansion does not apply</td><td><code>allowVolumeExpansion</code>, filesystem resize support, and whether the pod must restart.</td></tr><tr><td>Storage is slow</td><td>Underlying disk type, replication factor, node pressure, network bandwidth, and workload I/O pattern.</td></tr></tbody></table><p>Do not delete PVCs, PVs, <code>VolumeAttachment</code> resources, or storage-engine custom resources unless you administer the cluster and have confirmed the data is no longer needed or a restore path exists.</p><h2 id="destructive-disk-operations" tabindex="-1">Destructive Disk Operations <a class="header-anchor" href="#destructive-disk-operations" aria-label="Permalink to &quot;Destructive Disk Operations&quot;">​</a></h2><p>Some storage-engine recovery tasks require wiping disks or removing stale metadata. These operations are destructive and can permanently delete data for multiple workloads.</p><p>Before any disk wipe:</p><ol><li>Identify the exact node, disk, PV, PVC, and workload owners.</li><li>Confirm backup or acceptance of data loss.</li><li>Stop workloads that might write to the disk.</li><li>Record current storage-engine resources and events.</li><li>Run the storage-engine documented recovery procedure for the installed version.</li></ol><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./backup_restore.html">Backup and Restore</a></li><li><a href="./operations_runbooks.html">Operations Runbooks</a></li><li><a href="./../platform/object_storage.html">Object Storage</a></li></ul>`,27)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
